'use client'

import { useMemo } from 'react'
import type { SVGProps } from 'react'
import { useAppAuth } from '@/lib/frontend/auth/use-auth'
import { motion } from 'motion/react'
import { m } from '@/paraglide/messages.js'

/**
 * Empty chat state shown before the first message is sent.
 */
export function ChatWelcomeScreen({
  onSuggestionClick,
  disabled,
}: {
  onSuggestionClick: (prompt: string) => void
  disabled: boolean
}) {
  const { user } = useAppAuth()
  const displayName = user?.name ?? null

  const suggestions = useMemo(
    () => [
      {
        icon: <BrainPersonIcon className="h-6 w-6 text-violet-600" />,
        title: m.chat_welcome_suggestion_1_title(),
        prompt: m.chat_welcome_suggestion_1_prompt(),
      },
      {
        icon: <IdeaIcon className="h-6 w-6 text-yellow-600" />,
        title: m.chat_welcome_suggestion_2_title(),
        prompt: m.chat_welcome_suggestion_2_prompt(),
      },
      {
        icon: <GrowthIcon className="h-6 w-6 text-emerald-600" />,
        title: m.chat_welcome_suggestion_3_title(),
        prompt: m.chat_welcome_suggestion_3_prompt(),
      },
      {
        icon: <StudentIcon className="h-6 w-6 text-blue-600" />,
        title: m.chat_welcome_suggestion_4_title(),
        prompt: m.chat_welcome_suggestion_4_prompt(),
      },
      {
        icon: <LampIcon className="h-6 w-6 text-orange-600" />,
        title: m.chat_welcome_suggestion_5_title(),
        prompt: m.chat_welcome_suggestion_5_prompt(),
      },
      {
        icon: <DeskIcon className="h-6 w-6 text-green-600" />,
        title: m.chat_welcome_suggestion_6_title(),
        prompt: m.chat_welcome_suggestion_6_prompt(),
      },
    ],
    [],
  )

  return (
    <div className="w-full py-4 md:py-6">
      <div className="w-full max-w-2xl text-center">
        <div className="relative">
          <motion.h1
            className="mb-4 flex items-center justify-center text-4xl font-semibold text-foreground-strong"
            layout
          >
            {m.chat_welcome_greeting_prefix()}
            {displayName ? (
              <span className="relative ml-2 inline-block">
                <motion.span
                  className="relative inline-block font-semibold"
                  initial={{
                    opacity: 0,
                    x: -15,
                    scale: 0.95,
                    width: 0,
                  }}
                  animate={{
                    opacity: 1,
                    x: 0,
                    scale: 1,
                    width: 'auto',
                  }}
                  transition={{
                    duration: 1.2,
                    ease: [0.16, 1, 0.3, 1],
                    opacity: {
                      duration: 1.2,
                      ease: [0.16, 1, 0.3, 1],
                    },
                    x: {
                      duration: 1.2,
                      ease: [0.16, 1, 0.3, 1],
                    },
                    scale: {
                      duration: 1.2,
                      ease: [0.16, 1, 0.3, 1],
                    },
                    width: {
                      duration: 1.2,
                      ease: [0.16, 1, 0.3, 1],
                    },
                  }}
                  style={{
                    overflow: 'visible',
                    whiteSpace: 'nowrap',
                  }}
                >
                  {displayName}
                </motion.span>
                <motion.span
                  className="pointer-events-none absolute bottom-0 left-1/2 -translate-x-1/2 translate-y-1/2 text-blue-600"
                  initial={{
                    opacity: 0,
                    scale: 0.8,
                    y: -5,
                  }}
                  animate={{
                    opacity: 1,
                    scale: 1,
                    y: 0,
                  }}
                  transition={{
                    duration: 1.5,
                    delay: 1,
                    ease: [0.16, 1, 0.3, 1],
                  }}
                >
                  <DoddleLine className="h-20 w-38" />
                </motion.span>
              </span>
            ) : null}
          </motion.h1>
        </div>

        <h2 className="mb-8 text-3xl font-normal text-foreground-secondary">
          {m.chat_welcome_subtitle()}
        </h2>

        <div className="hidden gap-3 text-start md:grid md:grid-cols-2">
          {suggestions.map((item) => (
            <button
              key={item.title}
              type="button"
              onClick={() => onSuggestionClick(item.prompt)}
              disabled={disabled}
              className="rounded-3xl border border-border-base bg-surface-overlay p-4 text-start cursor-pointer hover:bg-surface-inverse/5 active:bg-surface-inverse/10 flex flex-col items-start"
            >
              <h3 className="mb-2 flex items-center gap-2 font-medium text-foreground-primary">
                {item.icon}
                {item.title}
              </h3>
              <p className="text-sm text-foreground-secondary">{item.prompt}</p>
            </button>
          ))}
        </div>
      </div>
    </div>
  )
}

